  (() => {
// 1. Sinaliza atividade para o sistema de segurança (reseta os 15 min)
 JSutils.resetInactivityTimer() // Para o Deletar, pegamos os dados reais da tabela (Source of Truth)
    const formData = 
     TablePelagem.selectedRow;
// Verificamos se existe um registro selecionado antes de abrir o modal
    if (!formData.pel001_id) {
      return showAlert("Selecione um registro na tabela para excluir.", "warning");
    }
    return JSconfirmation.showModal({
      action: "Delete",
      message: "Deseja realmente EXCLUIR o registro ?",
      icon: "trash",
      color: "red",
      row: formData
    });
  })()
}}
